"use client";

import { USER_COLORS } from "@/lib/types";

interface Stat {
  id: number;
  name: string;
  trip_count: number;
}

interface UsageStatsProps {
  stats: Stat[];
  year: number;
  availableYears: string[];
  onYearChange: (year: number) => void;
}

export default function UsageStats({ stats, year, availableYears, onYearChange }: UsageStatsProps) {
  const maxTrips = Math.max(...stats.map((s) => s.trip_count), 1);
  const totalTrips = stats.reduce((sum, s) => sum + s.trip_count, 0);

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-4 space-y-3">
      <div className="flex items-center justify-between">
        <h3 className="font-semibold text-gray-900 flex items-center gap-2">
          <span className="text-lg">📊</span> Usage
        </h3>
        <span className="text-xs text-gray-500">
          {totalTrips} total trips
        </span>
      </div>

      {/* Year picker */}
      <div className="flex items-center justify-center gap-3">
        <button
          onClick={() => onYearChange(year - 1)}
          className="p-1 hover:bg-gray-100 rounded-lg transition-colors text-gray-500"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
          </svg>
        </button>
        {availableYears.length > 2 ? (
          <select
            value={year}
            onChange={(e) => onYearChange(Number(e.target.value))}
            className="text-sm font-semibold text-gray-800 bg-transparent border-none cursor-pointer text-center focus:outline-none"
          >
            {availableYears.map((y) => (
              <option key={y} value={y}>{y}</option>
            ))}
          </select>
        ) : (
          <span className="text-sm font-semibold text-gray-800">{year}</span>
        )}
        <button
          onClick={() => onYearChange(year + 1)}
          className="p-1 hover:bg-gray-100 rounded-lg transition-colors text-gray-500"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
          </svg>
        </button>
      </div>

      {/* Stats bars */}
      <div className="space-y-1.5">
        {stats.map((stat) => (
          <div key={stat.id} className="flex items-center gap-2">
            <div
              className="w-6 h-6 rounded-full flex items-center justify-center text-white text-[10px] font-bold shrink-0"
              style={{ backgroundColor: USER_COLORS[stat.name] || "#6b7280" }}
            >
              {stat.name[0]}
            </div>
            <span className="text-xs text-gray-700 w-16 shrink-0 truncate">{stat.name}</span>
            <div className="flex-1 h-4 bg-gray-100 rounded-full overflow-hidden">
              <div
                className="h-full rounded-full transition-all duration-500"
                style={{
                  width: stat.trip_count > 0 ? `${Math.max((stat.trip_count / maxTrips) * 100, 8)}%` : "0%",
                  backgroundColor: USER_COLORS[stat.name] || "#6b7280",
                  opacity: stat.trip_count > 0 ? 1 : 0.2,
                }}
              />
            </div>
            <span className="text-xs font-medium text-gray-500 w-6 text-right">{stat.trip_count}</span>
          </div>
        ))}
      </div>

      {totalTrips === 0 && (
        <p className="text-center text-sm text-gray-400 py-2">No trips recorded for {year}</p>
      )}
    </div>
  );
}
