"use client";

import { useState } from "react";
import { FuelLog, User } from "@/lib/types";

interface FuelGaugeProps {
  current: {
    tank_level: number;
    jerry_cans_full: number;
    jerry_cans_empty: number;
  };
  history: FuelLog[];
  currentUser: User | null;
  onUpdate: (tankLevel: number, jerryFull: number, jerryEmpty: number) => void;
  saving?: boolean;
}

// Semicircular gauge component
function ArcGauge({ level, maxLevel = 8 }: { level: number; maxLevel?: number }) {
  const size = 200;
  const strokeWidth = 18;
  const cx = size / 2;
  const cy = size / 2 + 10; // offset down slightly so arc is centered visually
  const radius = (size - strokeWidth) / 2 - 8;

  // Arc from 180° to 0° (left to right, semicircle)
  const startAngle = Math.PI;
  const endAngle = 0;
  const sweepAngle = startAngle - endAngle;
  const fillAngle = startAngle - (level / maxLevel) * sweepAngle;

  const polarToCartesian = (angle: number) => ({
    x: cx + radius * Math.cos(angle),
    y: cy - radius * Math.sin(angle),
  });

  const bgStart = polarToCartesian(startAngle);
  const bgEnd = polarToCartesian(endAngle);
  const fillStart = polarToCartesian(startAngle);
  const fillEnd = polarToCartesian(fillAngle);

  // Determine if fill arc is > 180 degrees (for SVG large-arc-flag)
  const fillSweep = startAngle - fillAngle;
  const largeArc = fillSweep > Math.PI ? 1 : 0;

  // Color based on level
  const getColor = (l: number) => {
    if (l <= 2) return { main: "#ef4444", glow: "#fecaca" }; // red
    if (l <= 4) return { main: "#f59e0b", glow: "#fef3c7" }; // amber
    return { main: "#22c55e", glow: "#dcfce7" }; // green
  };

  const colors = getColor(level);

  // Tick marks at each eighth
  const ticks = Array.from({ length: maxLevel + 1 }, (_, i) => {
    const angle = startAngle - (i / maxLevel) * sweepAngle;
    const inner = radius - strokeWidth / 2 - 4;
    const outer = radius + strokeWidth / 2 + 4;
    return {
      x1: cx + inner * Math.cos(angle),
      y1: cy - inner * Math.sin(angle),
      x2: cx + outer * Math.cos(angle),
      y2: cy - outer * Math.sin(angle),
      label: i,
      lx: cx + (outer + 10) * Math.cos(angle),
      ly: cy - (outer + 10) * Math.sin(angle),
    };
  });

  // Needle position
  const needleAngle = startAngle - (level / maxLevel) * sweepAngle;
  const needleLength = radius - strokeWidth / 2 - 8;
  const needleTip = {
    x: cx + needleLength * Math.cos(needleAngle),
    y: cy - needleLength * Math.sin(needleAngle),
  };

  return (
    <svg viewBox={`0 0 ${size} ${size / 2 + 30}`} className="w-full max-w-[240px] mx-auto">
      <defs>
        <filter id="gaugeShadow" x="-10%" y="-10%" width="120%" height="120%">
          <feDropShadow dx="0" dy="1" stdDeviation="2" floodColor={colors.main} floodOpacity="0.3" />
        </filter>
      </defs>

      {/* Background arc */}
      <path
        d={`M ${bgStart.x} ${bgStart.y} A ${radius} ${radius} 0 0 1 ${bgEnd.x} ${bgEnd.y}`}
        fill="none"
        stroke="#e5e7eb"
        strokeWidth={strokeWidth}
        strokeLinecap="round"
      />

      {/* Fill arc */}
      {level > 0 && (
        <path
          d={`M ${fillStart.x} ${fillStart.y} A ${radius} ${radius} 0 ${largeArc} 1 ${fillEnd.x} ${fillEnd.y}`}
          fill="none"
          stroke={colors.main}
          strokeWidth={strokeWidth}
          strokeLinecap="round"
          filter="url(#gaugeShadow)"
          className="transition-all duration-700 ease-out"
        />
      )}

      {/* Tick marks */}
      {ticks.map((tick) => (
        <line
          key={tick.label}
          x1={tick.x1}
          y1={tick.y1}
          x2={tick.x2}
          y2={tick.y2}
          stroke="#d1d5db"
          strokeWidth={tick.label === 0 || tick.label === maxLevel ? 2 : 1}
        />
      ))}

      {/* Needle */}
      <line
        x1={cx}
        y1={cy}
        x2={needleTip.x}
        y2={needleTip.y}
        stroke="#374151"
        strokeWidth={2.5}
        strokeLinecap="round"
        className="transition-all duration-700 ease-out"
      />
      <circle cx={cx} cy={cy} r={5} fill="#374151" />
      <circle cx={cx} cy={cy} r={2.5} fill="#9ca3af" />

      {/* Center label */}
      <text
        x={cx}
        y={cy + 22}
        textAnchor="middle"
        className="text-xs"
        fill="#6b7280"
        fontSize="11"
        fontWeight="500"
      >
        {level}/{maxLevel}
      </text>

      {/* E and F labels */}
      <text
        x={ticks[0].lx - 2}
        y={ticks[0].ly + 4}
        textAnchor="end"
        fill="#9ca3af"
        fontSize="10"
        fontWeight="600"
      >
        E
      </text>
      <text
        x={ticks[maxLevel].lx + 2}
        y={ticks[maxLevel].ly + 4}
        textAnchor="start"
        fill="#9ca3af"
        fontSize="10"
        fontWeight="600"
      >
        F
      </text>
    </svg>
  );
}

export default function FuelGauge({ current, history, currentUser, onUpdate, saving = false }: FuelGaugeProps) {
  const [editing, setEditing] = useState(false);
  const [tankLevel, setTankLevel] = useState(current.tank_level);
  const [jerryFull, setJerryFull] = useState(current.jerry_cans_full);
  const [jerryEmpty, setJerryEmpty] = useState(current.jerry_cans_empty);

  const handleSave = () => {
    if (saving) return;
    onUpdate(tankLevel, jerryFull, jerryEmpty);
    setEditing(false);
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-4 space-y-4">
      <div className="flex items-center justify-between">
        <h3 className="font-semibold text-gray-900 flex items-center gap-2">
          <span className="text-lg">⛽</span> Diesel
        </h3>
      </div>

      {/* Semicircular fuel gauge */}
      <ArcGauge level={current.tank_level} />

      {/* Jerry cans */}
      <div className="flex items-center justify-center gap-4">
        <h4 className="text-sm font-medium text-gray-600 flex items-center gap-1.5">
          <span>🛢️</span> Jerry cans
        </h4>
        <div className="flex gap-3 text-sm">
          <span className="px-2 py-0.5 bg-green-50 text-green-700 rounded-md font-medium">
            {current.jerry_cans_full} full
          </span>
          <span className="px-2 py-0.5 bg-red-50 text-red-700 rounded-md font-medium">
            {current.jerry_cans_empty} empty
          </span>
        </div>
      </div>

      {/* Edit form */}
      {currentUser && !editing && (
        <button
          onClick={() => {
            setTankLevel(current.tank_level);
            setJerryFull(current.jerry_cans_full);
            setJerryEmpty(current.jerry_cans_empty);
            setEditing(true);
          }}
          className="w-full py-2 text-sm font-medium text-sky-600 hover:text-sky-700 hover:bg-sky-50 rounded-lg transition-colors"
        >
          Update after trip
        </button>
      )}

      {editing && (
        <div className="space-y-3 p-3 bg-gray-50 rounded-xl">
          <div>
            <label className="block text-xs font-medium text-gray-600 mb-1.5">
              Tank level
            </label>
            <div className="flex gap-1">
              {Array.from({ length: 9 }, (_, i) => (
                <button
                  key={i}
                  onClick={() => setTankLevel(i)}
                  className={`flex-1 py-1.5 text-xs font-medium rounded-md transition-colors ${
                    i === tankLevel
                      ? "bg-sky-600 text-white"
                      : i <= tankLevel
                        ? "bg-sky-100 border border-sky-200 text-sky-700"
                        : "bg-white border border-gray-200 text-gray-600 hover:bg-gray-50"
                  }`}
                >
                  {i}
                </button>
              ))}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-xs font-medium text-gray-600 mb-1">Full cans</label>
              <div className="flex items-center gap-2">
                <button
                  onClick={() => setJerryFull(Math.max(0, jerryFull - 1))}
                  className="w-8 h-8 rounded-lg bg-white border border-gray-200 text-gray-600 hover:bg-gray-50 flex items-center justify-center"
                >
                  −
                </button>
                <span className="w-8 text-center font-medium">{jerryFull}</span>
                <button
                  onClick={() => setJerryFull(Math.min(10, jerryFull + 1))}
                  className="w-8 h-8 rounded-lg bg-white border border-gray-200 text-gray-600 hover:bg-gray-50 flex items-center justify-center"
                >
                  +
                </button>
              </div>
            </div>
            <div>
              <label className="block text-xs font-medium text-gray-600 mb-1">Empty cans</label>
              <div className="flex items-center gap-2">
                <button
                  onClick={() => setJerryEmpty(Math.max(0, jerryEmpty - 1))}
                  className="w-8 h-8 rounded-lg bg-white border border-gray-200 text-gray-600 hover:bg-gray-50 flex items-center justify-center"
                >
                  −
                </button>
                <span className="w-8 text-center font-medium">{jerryEmpty}</span>
                <button
                  onClick={() => setJerryEmpty(Math.min(10, jerryEmpty + 1))}
                  className="w-8 h-8 rounded-lg bg-white border border-gray-200 text-gray-600 hover:bg-gray-50 flex items-center justify-center"
                >
                  +
                </button>
              </div>
            </div>
          </div>

          <div className="flex gap-2">
            <button
              onClick={() => setEditing(false)}
              disabled={saving}
              className="flex-1 py-2 text-sm rounded-lg bg-white border border-gray-200 text-gray-600 hover:bg-gray-50 disabled:opacity-50"
            >
              Cancel
            </button>
            <button
              onClick={handleSave}
              disabled={saving}
              className="flex-1 py-2 text-sm rounded-lg bg-sky-600 text-white hover:bg-sky-700 font-medium disabled:opacity-50"
            >
              {saving ? "Saving..." : "Save"}
            </button>
          </div>
        </div>
      )}

      {/* Recent history */}
      {history.length > 0 && (
        <div className="space-y-1">
          <h4 className="text-xs font-medium text-gray-500 uppercase tracking-wide">Recent updates</h4>
          <div className="space-y-1 max-h-32 overflow-y-auto">
            {history.slice(0, 5).map((log) => (
              <div key={log.id} className="flex items-center justify-between text-xs text-gray-500 py-1">
                <span>
                  <strong className="text-gray-700">{log.user_name}</strong> — Tank {log.tank_level}/8
                  {(log.jerry_cans_full > 0 || log.jerry_cans_empty > 0) &&
                    ` · ${log.jerry_cans_full}F/${log.jerry_cans_empty}E cans`
                  }
                </span>
                <span className="text-gray-400 ml-2 shrink-0">
                  {new Date(log.created_at).toLocaleDateString()}
                </span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}
