"use client";

import { useState, useCallback, useRef } from "react";
import { Reservation, User, USER_COLORS } from "@/lib/types";

interface CalendarProps {
  reservations: Reservation[];
  currentUser: User | null;
  onReserve: (date: string) => void;
  onCancel: (reservation: Reservation) => void;
  month: Date;
  onMonthChange: (date: Date) => void;
  saving?: boolean;
}

function getDaysInMonth(year: number, month: number): number {
  return new Date(year, month + 1, 0).getDate();
}

function getFirstDayOfMonth(year: number, month: number): number {
  // Return 0 = Monday ... 6 = Sunday
  const day = new Date(year, month, 1).getDay();
  return day === 0 ? 6 : day - 1;
}

function formatDate(year: number, month: number, day: number): string {
  return `${year}-${String(month + 1).padStart(2, "0")}-${String(day).padStart(2, "0")}`;
}

function formatFriendlyDate(dateStr: string): string {
  const [y, m, d] = dateStr.split("-").map(Number);
  const date = new Date(y, m - 1, d);
  const weekday = date.toLocaleDateString("en-US", { weekday: "short" });
  const month = date.toLocaleDateString("en-US", { month: "short" });
  return `${weekday} ${d} ${month}`;
}

const MONTH_NAMES = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December",
];

const DAY_NAMES = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"];

export default function Calendar({
  reservations,
  currentUser,
  onReserve,
  onCancel,
  month,
  onMonthChange,
  saving = false,
}: CalendarProps) {
  const [selectedDate, setSelectedDate] = useState<string | null>(null);
  const [slideDir, setSlideDir] = useState<"left" | "right" | null>(null);
  const touchStartX = useRef<number | null>(null);
  const touchStartY = useRef<number | null>(null);
  const year = month.getFullYear();
  const monthIndex = month.getMonth();
  const daysInMonth = getDaysInMonth(year, monthIndex);
  const firstDay = getFirstDayOfMonth(year, monthIndex);

  const today = new Date();
  const todayStr = formatDate(today.getFullYear(), today.getMonth(), today.getDate());

  // Check if we're viewing the current month
  const isCurrentMonth = year === today.getFullYear() && monthIndex === today.getMonth();

  const reservationMap = new Map<string, Reservation>();
  reservations.forEach((r) => reservationMap.set(r.date, r));

  const prevMonth = useCallback(() => {
    setSlideDir("right");
    const d = new Date(year, monthIndex - 1, 1);
    onMonthChange(d);
    setSelectedDate(null);
    setTimeout(() => setSlideDir(null), 250);
  }, [year, monthIndex, onMonthChange]);

  const nextMonth = useCallback(() => {
    setSlideDir("left");
    const d = new Date(year, monthIndex + 1, 1);
    onMonthChange(d);
    setSelectedDate(null);
    setTimeout(() => setSlideDir(null), 250);
  }, [year, monthIndex, onMonthChange]);

  const goToToday = useCallback(() => {
    onMonthChange(new Date());
    setSelectedDate(null);
  }, [onMonthChange]);

  // Touch swipe handlers for month navigation
  const handleTouchStart = useCallback((e: React.TouchEvent) => {
    touchStartX.current = e.touches[0].clientX;
    touchStartY.current = e.touches[0].clientY;
  }, []);

  const handleTouchEnd = useCallback((e: React.TouchEvent) => {
    if (touchStartX.current === null || touchStartY.current === null) return;
    const dx = e.changedTouches[0].clientX - touchStartX.current;
    const dy = e.changedTouches[0].clientY - touchStartY.current;
    touchStartX.current = null;
    touchStartY.current = null;

    // Only swipe if horizontal distance > 60px and more horizontal than vertical
    if (Math.abs(dx) > 60 && Math.abs(dx) > Math.abs(dy) * 1.5) {
      if (dx < 0) nextMonth();
      else prevMonth();
    }
  }, [nextMonth, prevMonth]);

  const handleDayClick = (dateStr: string) => {
    if (saving) return;

    const reservation = reservationMap.get(dateStr);

    if (reservation) {
      // If it's the current user's reservation, allow cancel
      if (currentUser && reservation.user_id === currentUser.id) {
        setSelectedDate(dateStr);
      } else {
        // Show info about who booked it
        setSelectedDate(dateStr);
      }
      return;
    }

    // If no reservation and user is logged in, reserve
    if (currentUser && dateStr >= todayStr) {
      setSelectedDate(dateStr);
    }
  };

  const days: Array<{ day: number | null; dateStr: string; dayOfWeek: number }> = [];

  // Empty cells for days before the first day of month
  for (let i = 0; i < firstDay; i++) {
    days.push({ day: null, dateStr: "", dayOfWeek: i });
  }

  // Actual days (dayOfWeek: 0=Mon ... 6=Sun, matching our grid)
  for (let d = 1; d <= daysInMonth; d++) {
    const idx = (firstDay + d - 1) % 7;
    days.push({ day: d, dateStr: formatDate(year, monthIndex, d), dayOfWeek: idx });
  }

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
      {/* Header */}
      <div className="flex items-center justify-between px-4 py-3 bg-sky-700 text-white">
        <button onClick={prevMonth} className="p-1 hover:bg-sky-600 rounded-lg transition-colors">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
          </svg>
        </button>
        <div className="flex items-center gap-2">
          <h2 className="text-lg font-semibold">
            {MONTH_NAMES[monthIndex]} {year}
          </h2>
          {!isCurrentMonth && (
            <button
              onClick={goToToday}
              className="text-[11px] font-medium bg-sky-600 hover:bg-sky-500 px-2 py-0.5 rounded-md transition-colors"
            >
              Today
            </button>
          )}
        </div>
        <button onClick={nextMonth} className="p-1 hover:bg-sky-600 rounded-lg transition-colors">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
          </svg>
        </button>
      </div>

      {/* Day headers */}
      <div className="grid grid-cols-7 bg-gray-50 border-b border-gray-100">
        {DAY_NAMES.map((name, i) => (
          <div key={name} className={`text-center text-xs font-medium py-2 ${
            i >= 5 ? "text-sky-500" : "text-gray-500"
          }`}>
            {name}
          </div>
        ))}
      </div>

      {/* Days grid */}
      <div
        className={`grid grid-cols-7 gap-px bg-gray-100 ${
          slideDir === "left" ? "animate-slideLeft" :
          slideDir === "right" ? "animate-slideRight" : ""
        }`}
        onTouchStart={handleTouchStart}
        onTouchEnd={handleTouchEnd}
      >
        {days.map(({ day, dateStr, dayOfWeek }, i) => {
          const isWeekend = dayOfWeek >= 5; // Sat=5, Sun=6

          if (day === null) {
            return <div key={`empty-${i}`} className={`min-h-[2.75rem] sm:min-h-[3.5rem] ${isWeekend ? "bg-sky-50/50" : "bg-white"}`} />;
          }

          const reservation = reservationMap.get(dateStr);
          const isToday = dateStr === todayStr;
          const isPast = dateStr < todayStr;
          const isSelected = dateStr === selectedDate;

          return (
            <button
              key={dateStr}
              onClick={() => handleDayClick(dateStr)}
              disabled={!currentUser || (isPast && !reservation) || saving}
              className={`
                relative min-h-[2.75rem] sm:min-h-[3.5rem] p-1 flex flex-col items-center transition-all
                ${isWeekend ? "bg-sky-50/50" : "bg-white"}
                ${isPast && !reservation ? "opacity-40" : ""}
                ${!reservation && currentUser && !isPast && !saving ? "hover:bg-sky-50 active:bg-sky-100 cursor-pointer" : ""}
                ${reservation && currentUser ? "cursor-pointer" : ""}
                ${isSelected ? "ring-2 ring-sky-500 ring-inset" : ""}
              `}
            >
              <span
                className={`text-xs font-medium w-5 h-5 flex items-center justify-center rounded-full ${
                  isToday
                    ? "bg-sky-600 text-white"
                    : isWeekend
                      ? "text-sky-700"
                      : "text-gray-700"
                }`}
              >
                {day}
              </span>

              {reservation && (
                <div
                  className="mt-0.5 w-full rounded-md px-1 py-0.5 text-center"
                  style={{
                    backgroundColor: USER_COLORS[reservation.user_name || ""] + "20",
                    borderLeft: `3px solid ${USER_COLORS[reservation.user_name || ""] || "#6b7280"}`,
                  }}
                >
                  <span className="text-[10px] font-medium leading-tight block truncate" style={{
                    color: USER_COLORS[reservation.user_name || ""] || "#6b7280",
                  }}>
                    {reservation.user_name}
                  </span>
                </div>
              )}
            </button>
          );
        })}
      </div>

      {/* Upcoming reservations summary */}
      {(() => {
        const upcoming = reservations
          .filter((r) => r.date >= todayStr)
          .sort((a, b) => a.date.localeCompare(b.date))
          .slice(0, 3);

        if (upcoming.length === 0) return null;

        return (
          <div className="px-3 py-2 border-t border-gray-100">
            <p className="text-[10px] font-medium text-gray-400 uppercase tracking-wide mb-1">Upcoming</p>
            <div className="space-y-1">
              {upcoming.map((r) => (
                <div key={r.id} className="flex items-center gap-2 text-xs">
                  <div
                    className="w-2 h-2 rounded-full shrink-0"
                    style={{ backgroundColor: USER_COLORS[r.user_name || ""] || "#6b7280" }}
                  />
                  <span className="text-gray-500">{formatFriendlyDate(r.date)}</span>
                  <span className="font-medium text-gray-700">{r.user_name}</span>
                </div>
              ))}
            </div>
          </div>
        );
      })()}

      {/* Action bar */}
      {selectedDate && currentUser && (() => {
        const selectedReservation = reservationMap.get(selectedDate);
        const isOwnReservation = selectedReservation && selectedReservation.user_id === currentUser.id;
        const isOtherReservation = selectedReservation && selectedReservation.user_id !== currentUser.id;

        return (
          <div className="p-3 bg-sky-50 border-t border-sky-100 flex items-center justify-between">
            {isOwnReservation ? (
              <>
                <span className="text-sm text-gray-700">
                  Cancel <strong>{formatFriendlyDate(selectedDate)}</strong>?
                </span>
                <div className="flex gap-2">
                  <button
                    onClick={() => setSelectedDate(null)}
                    disabled={saving}
                    className="px-3 py-1.5 text-sm rounded-lg bg-white border border-gray-200 text-gray-600 hover:bg-gray-50 disabled:opacity-50"
                  >
                    No
                  </button>
                  <button
                    onClick={() => {
                      onCancel(selectedReservation);
                      setSelectedDate(null);
                    }}
                    disabled={saving}
                    className="px-3 py-1.5 text-sm rounded-lg bg-red-500 text-white hover:bg-red-600 disabled:opacity-50"
                  >
                    Cancel it
                  </button>
                </div>
              </>
            ) : isOtherReservation ? (
              <>
                <div className="flex items-center gap-2 text-sm text-gray-700">
                  <div
                    className="w-5 h-5 rounded-full flex items-center justify-center text-white text-[9px] font-bold shrink-0"
                    style={{ backgroundColor: USER_COLORS[selectedReservation.user_name || ""] || "#6b7280" }}
                  >
                    {(selectedReservation.user_name || "?")[0]}
                  </div>
                  <span>
                    <strong>{selectedReservation.user_name}</strong> has {formatFriendlyDate(selectedDate)}
                  </span>
                </div>
                <button
                  onClick={() => setSelectedDate(null)}
                  className="px-3 py-1.5 text-sm rounded-lg bg-white border border-gray-200 text-gray-600 hover:bg-gray-50"
                >
                  OK
                </button>
              </>
            ) : (
              <>
                <span className="text-sm text-gray-700">
                  Reserve <strong>{formatFriendlyDate(selectedDate)}</strong>?
                </span>
                <div className="flex gap-2">
                  <button
                    onClick={() => setSelectedDate(null)}
                    disabled={saving}
                    className="px-3 py-1.5 text-sm rounded-lg bg-white border border-gray-200 text-gray-600 hover:bg-gray-50 disabled:opacity-50"
                  >
                    No
                  </button>
                  <button
                    onClick={() => {
                      onReserve(selectedDate);
                      setSelectedDate(null);
                    }}
                    disabled={saving}
                    className="px-3 py-1.5 text-sm rounded-lg bg-sky-600 text-white hover:bg-sky-700 disabled:opacity-50"
                  >
                    Reserve
                  </button>
                </div>
              </>
            )}
          </div>
        );
      })()}
    </div>
  );
}
